using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;
using BenchmarkDotNet.Environments;
using BenchmarkDotNet.Jobs;
using BenchmarkDotNet.Running;
using TextAnalysis;

var config = DefaultConfig.Instance
    .AddJob(Job.Default.WithRuntime(CoreRuntime.Core90).WithId("net9.0"))
    .AddJob(Job.Default.WithRuntime(CoreRuntime.Core100).WithId("net10.0"));

BenchmarkRunner.Run<TextAnalyzerBenchmarks>(config);

[MemoryDiagnoser]
public class TextAnalyzerBenchmarks
{
    private TextAnalyzer _analyzer = null!;

    [GlobalSetup]
    public void Setup()
    {
        // A representative paragraph with varied word lengths
        var text = string.Join(" ", Enumerable.Repeat(
            "The quick brown fox jumps over the lazy dog while the magnificent " +
            "elephants gracefully traversed the extraordinarily beautiful landscape " +
            "underneath a spectacular cerulean sky illuminated by countless stars",
            100));
        _analyzer = new TextAnalyzer(text);
    }

    [Benchmark]
    public double AverageWordLength() => _analyzer.AverageWordLength();

    [Benchmark]
    public object WordLengthHistogram() => _analyzer.WordLengthHistogram();

    [Benchmark]
    public int UniqueWordCount() => _analyzer.UniqueWordCount();
}

